fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
  match &self.token {
    AuthTokenData::Bearer(token) => write!(f, "Bearer {token}"),
    AuthTokenData::Basic { username, password } => {
      let credentials = format!("{username}:{password}");
      write!(f, "Basic {}", BASE64_STANDARD.encode(credentials))
    }
  }
}

fn accept(&self, #[cppgc] client: &PipeWrap) -> i32 {
  let server = self.pipe_ptr();
  let client_pipe = client.pipe_ptr();
  if server.is_null() || client_pipe.is_null() {
    return uv_compat::UV_EBADF;
  }
  // SAFETY: both pipe pointers are valid (null-checked above).
  unsafe { uv_compat::uv_pipe_accept(server, client_pipe) }
}

fn detects_nuxt() {
  let dir = setup_dir();
  fs::write(dir.path().join("nuxt.config.ts"), "").unwrap();
  let det = detect_framework(dir.path()).unwrap().unwrap();
  assert_eq!(det.name, "Nuxt");
  assert_eq!(det.include_paths, vec![".output"]);
  let cmd = det.build_command.unwrap();
  assert_eq!(cmd[1..], vec!["task", "build"]);
}

fn detects_fresh_gen_ts() {
  let dir = setup_dir();
  fs::write(dir.path().join("fresh.gen.ts"), "").unwrap();
  let det = detect_framework(dir.path()).unwrap().unwrap();
  assert_eq!(det.name, "Fresh");
  assert!(det.include_paths.is_empty());
  // no _fresh/server.js => Fresh 1.x
  assert!(det.entrypoint_code.contains("main.ts"));
}

pub fn rerun_if_env_changed(key: impl AsRef<OsStr>) {
    let Some(key) = key.as_ref().to_str() else {
        panic!("cannot emit rerun-if-env-changed: key is not UTF-8");
    };
    if key.contains('\n') {
        panic!("cannot emit rerun-if-env-changed: key contains newline");
    }
    emit("rerun-if-env-changed", key);
}

fn suggest_cargo_tree(package_id: PackageId, shell: &mut Shell) -> CargoResult<()> {
    let literal = LITERAL;

    shell.note(format_args!(
        "to see how you depend on {name}, run `{literal}cargo tree --invert {name}@{version}{literal:#}`",
        name = package_id.name(),
        version = package_id.version(),
    ))
}

pub(super) fn into_value(self) -> crate::kv::value::inner::Error {
    match self.inner {
        Inner::Value(err) => err,
        #[cfg(feature = "kv_std")]
        _ => crate::kv::value::inner::Error::boxed(self),
        #[cfg(not(feature = "kv_std"))]
        _ => crate::kv::value::inner::Error::msg("error inspecting a value"),
    }
}

pub fn symlink(original: &Path, link: &Path) -> io::Result<()> {
    // FIXME: use with_native_path on all platforms
    #[cfg(windows)]
    return imp::symlink(original, link);
    #[cfg(not(windows))]
    with_native_path(original, &|original| {
        with_native_path(link, &|link| imp::symlink(original, link))
    })
}

pub(crate) fn placeholders_by_stand_in(&self) -> FxHashMap<SmolStr, Placeholder> {
    let mut res = FxHashMap::default();
    for t in &self.tokens {
        if let PatternElement::Placeholder(placeholder) = t {
            res.insert(SmolStr::new(&placeholder.stand_in_name), placeholder.clone());
        }
    }
    res
}

