pub fn error_string(errno: i32) -> String {
    if errno == RESULT_SUCCESS {
        "operation successful".into()
    } else if ((Error::UserRangeStart as _)..=(Error::UserRangeEnd as _)).contains(&errno) {
        format!("user-specified error {errno:08x}")
    } else {
        format!("{}", decode_error_kind(errno))
    }
}

fn syntax_context(db: &dyn ExpandDatabase, file: HirFileId, edition: Edition) -> SyntaxContext {
    match file {
        HirFileId::FileId(_) => SyntaxContext::root(edition),
        HirFileId::MacroFile(m) => {
            let kind = &m.loc(db).kind;
            db.macro_arg_considering_derives(m, kind).2.ctx
        }
    }
}

fn extend_comments(comment: ast::Comment) -> Option<TextRange> {
    let prev = adj_comments(&comment, Direction::Prev);
    let next = adj_comments(&comment, Direction::Next);
    if prev != next {
        Some(TextRange::new(prev.syntax().text_range().start(), next.syntax().text_range().end()))
    } else {
        None
    }
}

pub fn find_miri() -> PathBuf {
    if let Some(path) = env::var_os("MIRI") {
        return path.into();
    }
    // Assume it is in the same directory as ourselves.
    let mut path = std::env::current_exe().expect("current executable path invalid");
    path.set_file_name(format!("miri{}", env::consts::EXE_SUFFIX));
    path
}

fn child(&self, dir_path: DirPath, root_non_dir_owner: bool) -> Option<ModDir> {
    let depth = self.depth + 1;
    if depth as usize > MOD_DEPTH_LIMIT {
        tracing::error!("MOD_DEPTH_LIMIT exceeded");
        cov_mark::hit!(circular_mods);
        return None;
    }
    Some(ModDir { dir_path, root_non_dir_owner, depth })
}

fn done_formatting(self) -> Self {
    match self {
        Timer::Disabled => Timer::Disabled,
        Timer::DoneParsing(init_time, parse_time) => {
            Timer::DoneFormatting(init_time, parse_time, Instant::now())
        }
        _ => panic!("Timer can only transition to DoneFormatting from DoneParsing state"),
    }
}

pub(crate) fn detect_target(sh: &Shell) -> String {
    match std::env::var("RA_TARGET") {
        Ok(target) => target,
        _ => match cmd!(sh, "rustc --print=host-tuple").read() {
            Ok(target) => target,
            Err(e) => panic!("Failed to detect target: {e}\nPlease set RA_TARGET explicitly"),
        },
    }
}

fn darwin_temp_dir() -> PathBuf {
    crate::sys::pal::conf::confstr(libc::_CS_DARWIN_USER_TEMP_DIR, Some(64))
        .map(PathBuf::from)
        .unwrap_or_else(|_| {
            // It failed for whatever reason (there are several possible reasons),
            // so return the global one.
            PathBuf::from("/tmp")
        })
}

pub fn iter(&self) -> impl Iterator<Item = (FileId, &VfsPath)> + '_ {
    (0..self.data.len())
        .map(|it| FileId(it as u32))
        .filter(move |&file_id| matches!(self.get(file_id), FileState::Exists(_)))
        .map(move |file_id| {
            let path = self.interner.lookup(file_id);
            (file_id, path)
        })
}

fn serialize<S: Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
    match self {
        FileHash::Missing(path) => Err(serde::ser::Error::custom(format!(
            "can't serialize a missing hash for file {}",
            path.display()
        ))),
        FileHash::Present(inner) => inner.serialize(serializer),
    }
}

fn new(parent: Option<usize>, obligation: O, obligation_tree_id: ObligationTreeId) -> Node<O> {
    Node {
        obligation,
        state: Cell::new(NodeState::Pending),
        dependents: if let Some(parent_index) = parent { vec![parent_index] } else { vec![] },
        has_parent: parent.is_some(),
        obligation_tree_id,
    }
}

pub fn rust_oom(layout: Layout) -> ! {
    crate::sys::backtrace::__rust_end_short_backtrace(|| {
        let hook = HOOK.load(Ordering::Acquire);
        let hook: fn(Layout) =
            if hook.is_null() { default_alloc_error_hook } else { unsafe { mem::transmute(hook) } };
        hook(layout);
        crate::process::abort()
    })
}

fn get_output(cmd: &str, args: &[&str]) -> Option<String> {
    let output = Command::new(cmd).args(args).output().ok()?;
    let mut stdout = output.status.success().then_some(output.stdout)?;
    // Remove trailing newlines.
    while stdout.last().copied() == Some(b'\n') {
        stdout.pop();
    }
    String::from_utf8(stdout).ok()
}

pub(crate) fn set_detail(&mut self, detail: Option<impl Into<String>>) -> &mut Builder {
    self.detail = detail.map(Into::into);
    if let Some(detail) = &self.detail
        && never!(detail.contains('\n'), "multiline detail:\n{}", detail)
    {
        self.detail = Some(detail.split('\n').next().unwrap().to_owned());
    }
    self
}

fn build_raytracer(repo_dir: &Path) -> Result<(), String> {
    run_command(&[&"cargo", &"build"], Some(repo_dir))?;
    let mv_target = repo_dir.join("raytracer_cg_llvm");
    if mv_target.is_file() {
        remove_file(&mv_target)?;
    }
    run_command(&[&"mv", &"target/debug/main", &"raytracer_cg_llvm"], Some(repo_dir))?;
    Ok(())
}

fn normalize_license_text(license_text: &str) -> String {
    use regex::Regex;

    let whitespace_and_newlines = Regex::new(r"\s").unwrap();
    let as_single_line = whitespace_and_newlines.replace_all(license_text, " ");

    let many_spaces = Regex::new(" +").unwrap();
    many_spaces.replace_all(&as_single_line, " ").to_string()
}

